from vex import verify

result = research_graph.invoke({
    "messages": [{"role": "user", "content": "Latest AI research breakthroughs?"}],
    "confidence": 0.0
})

# Vex verifies claims, sources, recency, bias
verified_result = verify(
    result['summary'],
    context={
        "sources": result['sources'],
        "use_case": "research_agent",
        "checks": ["source_verification", "claim_accuracy", "recency", "bias_detection"]
    },
    risk_profile="medium"
)

if verified_result.status == "approved":
    print(verified_result.output)
else:
    print(f"Blocked: {verified_result.issues}")

def safe_router(state: VerifiedResearchState) -> Literal["search", "vex_verify", END]:
    if state['iteration_count'] >= 5:
        return END  # Circuit breaker

    if state['confidence'] >= 0.85:
        return "synthesize"

    return "search"

@vex_node
def quality_gate_node(state: VerifiedResearchState) -> VerifiedResearchState:
    # Vex final verification with strict thresholds
    response = vex_client.verify(
        state['summary'],
        risk_profile="medium",
        min_score=0.8,
        max_issues=2
    )

    if response.status != "approved":
        raise ValueError(f"Quality gate failed: {response.issues}")

    return state

graph.add_conditional_edges("router", safe_router,
    {"search": "search", "synthesize": "quality_gate", END: END})
graph.add_node("quality_gate", quality_gate_node)
graph.add_edge("quality_gate", END)
